INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Integrated Git hosting$q$, $q$Full Git repository management with per-commit, symbol-aware code search and navigation.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Visual CI/CD engine$q$, $q$Kubernetes-native, Docker-first build pipelines configurable through a GUI instead of YAML, with matrix jobs and reusable job logic.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Kanban issue tracking$q$, $q$Customizable issue states, fields, and links, with an email-based service desk for external issue creation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Built-in package registries$q$, $q$Native support for Docker, NPM, Maven, NuGet, PyPI, RubyGems, and Helm packages without a separate artifact server.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Inline code commenting$q$, $q$Comment on any code snippet directly, independent of pull requests, for lightweight code review.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Enterprise security scanning$q$, $q$Vulnerability and secret scanning available in the Enterprise Edition for compliance-focused teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$SSO and directory integration$q$, $q$LDAP, Active Directory, single sign-on, and two-factor authentication available in the free Community Edition.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Community Edition is fully free and open source with no artificial feature caps on the core toolchain$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Combines Git hosting, CI/CD, issue tracking, and package registries in one lightweight self-hosted app$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Visual CI/CD job builder lowers the barrier to writing pipelines compared to YAML-only tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Active development with frequent releases and a sizeable open-source community$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Simple single-Docker-image deployment keeps self-hosting overhead low$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Smaller ecosystem and community than GitLab or GitHub, meaning fewer third-party integrations$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Enterprise features like HA clustering and security scanning require a paid per-user license$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Maintained primarily by a small core team rather than a large corporate backer$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Documentation and learning resources are less extensive than more established DevOps platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Java-based runtime can be heavier on resources than lighter Git servers like Gitea$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Is OneDev really free to use?$q$, $q$Yes. The OneDev Community Edition is free and open source under its published license, and includes Git hosting, CI/CD, issue tracking, code search, and package registries. Only the Enterprise Edition, which adds features like high availability and security scanning, requires a paid subscription.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$What is included in OneDev Enterprise Edition?$q$, $q$Enterprise Edition costs $6 per user per month with a 12 user-month minimum, and adds high-availability clustering, cross-project code search, vulnerability and secret scanning, audit logging, time tracking, a web terminal for CI/CD debugging, and priority support.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$How is OneDev different from GitLab?$q$, $q$OneDev is a lighter-weight, single-binary self-hosted alternative that bundles Git hosting, CI/CD, and issue tracking similarly to GitLab, but with a smaller footprint, a visual CI/CD job builder, and a smaller (though active) open-source community compared to GitLab's much larger ecosystem.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Can OneDev run CI/CD jobs without writing YAML?$q$, $q$Yes. OneDev provides a GUI for building CI/CD jobs with typed parameters, matrix jobs, and reusable logic, though YAML-based pipeline definitions are also supported for teams that prefer them.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Does OneDev support Docker and package registries?$q$, $q$Yes. OneDev includes built-in registries for Docker, NPM, Maven, NuGet, PyPI, RubyGems, and Helm packages, eliminating the need for a separate artifact repository like Nexus or Artifactory.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$How do I deploy OneDev?$q$, $q$OneDev ships as a single Docker image and can also be installed as a standalone application or deployed on Kubernetes, making self-hosting straightforward for teams of any size.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Who maintains OneDev?$q$, $q$OneDev was created by developer Robin Shen and is maintained as an active open-source project on GitHub, with nearly 500 releases and over 15,000 stars as of 2026.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Self-hosted Git and CI/CD for small engineering teams$q$, $q$Small teams replace separate GitHub, Jenkins, and Jira subscriptions with one free, self-hosted OneDev instance covering source control, builds, and issue tracking.$q$, $q$Startups and small engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Compliance-driven internal DevOps platform$q$, $q$Organizations with data residency or compliance requirements self-host OneDev Enterprise for full control over source code, build infrastructure, and audit trails.$q$, $q$Regulated enterprises and government teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Package and artifact consolidation$q$, $q$Teams use OneDev's built-in Docker, NPM, and Maven registries to avoid running a separate package manager server alongside their Git host.$q$, $q$DevOps and platform engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Git hosting and code search","Built-in CI/CD engine","Kanban issue tracking","Package registries (Docker, NPM, Maven, NuGet, PyPI, RubyGems, Helm)","LDAP/Active Directory, SSO, two-factor authentication"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$Enterprise Edition$q$, $q$$6/user/month (12 user-month minimum)$q$, $q$Monthly$q$, NULL, $q$["High availability clustering","Cross-project code search","Security and secret scanning","Audit logging","Time tracking and timesheets","Web terminal for CI/CD debugging","Priority email support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OneDev is a self-hosted, open-source DevOps platform that combines a Git server, CI/CD engine, issue tracker with kanban boards, code search, and package registries into one unified application. It was built to reduce the sprawl that comes from wiring together separate tools like GitHub, Jenkins, and Jira.$q$, $q$Because every feature shares the same underlying data model, teams can navigate seamlessly between commits, pull requests, CI/CD build logs, and issues. The project is written in Java, ships as a single Docker image, and is actively maintained with frequent releases.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OneDev's CI/CD engine is Kubernetes-native and Docker-first, with a visual job builder that lets teams define pipelines without hand-writing YAML, plus support for matrix jobs, typed parameters, and reusable job logic.$q$, $q$Built-in package registries cover Docker, NPM, Maven, NuGet, PyPI, RubyGems, and Helm, so teams do not need a separate artifact repository. Code search works per-commit by symbol, file name, or regular expression, and pull requests support inline commenting on any code snippet, not just diff lines.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community Edition is free and open source, and includes the full DevOps toolchain: Git hosting, CI/CD, issue tracking, code search, and package registries, plus LDAP/Active Directory authentication and single sign-on.$q$, $q$The Enterprise Edition costs $6 per user per month with a 12 user-month minimum purchase, and layers on high availability, security and secret scanning, audit logging, time tracking, and priority support for organizations with compliance or scale requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Live collaborative contract editing$q$, $q$Both parties can edit and comment on contract content in a shared digital document before signing, instead of exchanging static PDF redlines.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Data-driven contracts$q$, $q$Every contract field is captured as structured data, feeding dashboards, reporting, and downstream systems instead of being locked inside a PDF.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$E-signatures with compliance levels$q$, $q$Supports standard, advanced, and qualified e-signature levels to meet EU and other regional legal requirements.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Template management$q$, $q$Reusable, branded contract templates speed up creation for sales, HR, and procurement teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Workflow automation and approvals$q$, $q$Configurable approval chains and automated reminders reduce manual follow-up on contract status.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$CRM and business tool integrations$q$, $q$Native integrations with Salesforce, HubSpot, and Microsoft Dynamics keep contract data in sync with the rest of the sales stack.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Contract analytics$q$, $q$Dashboards surface contract value, cycle time, and renewal data for legal and revenue operations teams.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Live, collaborative editing feels more natural than redlining static PDF documents$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Free tier makes basic e-signing accessible without a paid commitment$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Publicly traded company provides financial transparency uncommon among CLM competitors$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Strong native integrations with popular CRM platforms like Salesforce and HubSpot$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Contract data is structured and reportable rather than locked in unstructured documents$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Advanced contract lifecycle management features require the higher-priced Business or Enterprise tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Smaller global brand recognition compared to DocuSign or Adobe Sign$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Some users report a learning curve when moving from simple e-signature tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Deeper customization and integrations may require Enterprise-tier custom pricing$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Primarily strongest in European markets, with less mature localization elsewhere$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Is Oneflow free to use?$q$, $q$Oneflow offers a free plan that allows sending and signing basic PDF contracts at no cost. More advanced features like data-driven digital contracts, templates, and lifecycle management require a paid Essentials, Business, or Enterprise plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$How much does Oneflow cost?$q$, $q$Oneflow's Essentials plan starts at around EUR17 per user per month for digital contracts and templates, while the Business plan is around EUR45 per user per month and adds lifecycle management and premium integrations. Enterprise pricing is custom.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$What makes Oneflow different from DocuSign?$q$, $q$Oneflow treats contracts as live, editable, structured data that both parties can co-edit before signing, whereas traditional e-signature tools like DocuSign are generally built around signing static PDF or Word documents.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Is Oneflow a publicly traded company?$q$, $q$Yes. Oneflow AB has been listed on Nasdaq First North Premier Growth Market in Stockholm since April 2022, making its financials publicly disclosed.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Does Oneflow integrate with Salesforce and HubSpot?$q$, $q$Yes, Oneflow offers native integrations with major CRM platforms including Salesforce, HubSpot, and Microsoft Dynamics to keep contract data synchronized with sales pipelines.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Are Oneflow e-signatures legally binding?$q$, $q$Yes. Oneflow supports multiple e-signature compliance levels, including advanced and qualified electronic signatures, to meet legal requirements in the EU and other regions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Who founded Oneflow?$q$, $q$Oneflow was founded in 2012 in Stockholm, Sweden by Anders Hamnes, Kalle Moodh, and Fredrik Rinman.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Sales contract acceleration$q$, $q$Sales teams use Oneflow to draft, negotiate, and close deals faster with live editing and instant e-signatures synced to their CRM.$q$, $q$B2B sales teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$HR onboarding and employment contracts$q$, $q$HR departments send templated employment agreements and offer letters for e-signature with automated tracking of completion status.$q$, $q$HR and people operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Procurement and vendor agreement management$q$, $q$Procurement teams manage vendor contract lifecycles, renewal reminders, and approval workflows in one auditable system.$q$, $q$Procurement and legal teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Send and sign basic PDF contracts","Limited templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Essentials$q$, $q$~EUR17/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Digital, data-driven contracts","Templates","Basic e-signatures"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Business$q$, $q$~EUR45/user/month$q$, $q$Monthly or annual$q$, NULL, $q$["Contract lifecycle management","Advanced workflow automation","Premium CRM integrations"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Dedicated support","Advanced security and compliance","API access","Custom contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Oneflow is a contract lifecycle management platform built around the idea that contracts should be structured, editable data rather than static documents. Founded in Stockholm in 2012, the company has grown into a publicly traded SaaS business listed on Nasdaq First North Premier Growth Market since 2022.$q$, $q$The platform lets sales, legal, HR, and procurement teams draft, negotiate, e-sign, and manage contracts in one place, with every contract field trackable for reporting and integration with CRM and ERP tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Oneflow's signature feature is its live, collaborative contract editor, where both parties can edit and comment on contract terms in real time before signing, rather than exchanging redlined PDF versions.$q$, $q$The platform also includes customizable templates, legally binding e-signatures with multiple compliance levels, approval workflows, contract analytics dashboards, and native integrations with tools like Salesforce, HubSpot, and Microsoft Dynamics.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5508cca3-5bae-43ef-99a9-12d8e8bc4e09', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Oneflow offers a free tier for basic PDF sending and signing, making it accessible for very small teams or occasional use.$q$, $q$Paid plans scale from Essentials (around EUR17/user/month) for digital contracts and templates, to Business (around EUR45/user/month) for full lifecycle management and premium integrations, up to custom Enterprise pricing for large organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Free-form note canvas$q$, $q$Click anywhere on a page to type, draw, or paste content without a fixed layout structure.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Handwriting and ink support$q$, $q$Native pen and touch input for handwritten notes and sketches on Surface and other pen-enabled devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Web clipper$q$, $q$Browser extension for saving web pages, articles, and images directly into a OneNote notebook.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Cross-device sync via OneDrive$q$, $q$Notes automatically sync across Windows, macOS, iOS, Android, and the web.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Audio recording with searchable notes$q$, $q$Record audio during meetings or lectures and search text notes taken alongside the recording.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Outlook and Teams integration$q$, $q$Attach meeting notes directly to Outlook calendar events and Microsoft Teams meetings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Copilot AI assistance$q$, $q$Microsoft 365 subscribers can use Copilot to summarize, organize, and draft content from notes.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Completely free standalone app with no forced subscription to get core note-taking functionality$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Best-in-class handwriting and ink support for pen-enabled Windows and Surface devices$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Deep integration with Outlook, Teams, and the rest of Microsoft 365$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Flexible free-form canvas suits both structured and unstructured note-taking styles$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Reliable cross-device sync via OneDrive$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Less suited to building structured databases or wikis compared to tools like Notion$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$AI features (Copilot) require a paid Microsoft 365 subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Microsoft has shifted app versions over the years (retiring OneNote for Windows 10 in 2025), which has confused some long-time users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Free-form canvas can become disorganized for users who prefer strict outlines or hierarchies$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Advanced search and tagging features lag behind dedicated knowledge-management tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Is OneNote still free in 2026?$q$, $q$Yes. OneNote's standalone app remains free, including unlimited notes and 5GB of OneDrive storage. A Microsoft 365 subscription is only required for premium features like Copilot AI assistance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Is Microsoft discontinuing OneNote?$q$, $q$No. Microsoft retired the separate 'OneNote for Windows 10' app in October 2025, but the main OneNote desktop and web apps continue to receive updates and new features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$How much does Microsoft 365 cost for OneNote's AI features?$q$, $q$Microsoft 365 plans that unlock Copilot features in OneNote range from $9.99/month (Personal) to $12.99/month (Family) to $19.99/month (Premium) as of 2026.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$When was OneNote first released?$q$, $q$OneNote was announced in late 2002 and first released in 2003, initially as a standalone product before becoming part of the core Office suite starting with Office 2007.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Can I use OneNote without a Microsoft account?$q$, $q$A Microsoft account is required to sync notebooks across devices via OneDrive, though local note-taking is possible without full cloud sync in some configurations.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$What is the difference between OneNote and Notion?$q$, $q$OneNote focuses on free-form note capture, handwriting, and Microsoft 365 integration, while Notion emphasizes structured databases, wikis, and team collaboration workflows. OneNote is free standalone; Notion has its own separate freemium pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Does OneNote support handwriting and drawing?$q$, $q$Yes, OneNote has strong native support for pen and touch input, making it popular on Surface devices and other pen-enabled tablets and laptops.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Student lecture and research notes$q$, $q$Students use OneNote's free-form canvas and handwriting support to capture lecture notes, diagrams, and research clippings in organized notebooks.$q$, $q$Students and educators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Meeting notes tied to Outlook and Teams$q$, $q$Professionals attach OneNote pages directly to Outlook calendar invites and Teams meetings to keep meeting notes linked to context.$q$, $q$Business professionals and teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Personal knowledge capture and web clipping$q$, $q$Individuals use the OneNote Web Clipper to save articles, receipts, and reference material into searchable, synced notebooks.$q$, $q$Individual knowledge workers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$OneNote Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited notes","5GB OneDrive storage","Cross-device sync","Web clipper"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Microsoft 365 Personal$q$, $q$$9.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Copilot AI features in OneNote","Full Office app suite","Expanded OneDrive storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Microsoft 365 Family$q$, $q$$12.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 6 users","Copilot AI features","Full Office app suite","Expanded shared OneDrive storage"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$Microsoft 365 Premium$q$, $q$$19.99/month$q$, $q$Monthly or annual$q$, NULL, $q$["Advanced Copilot AI features","Full Office app suite","Priority support","Expanded OneDrive storage"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OneNote is Microsoft's free-form digital notebook, first released in 2003 and now a core part of the Microsoft 365 ecosystem. It lets users capture typed notes, handwriting, audio, images, and clipped web pages, organized into notebooks, sections, and pages that sync across devices via OneDrive.$q$, $q$Unlike many competitors, OneNote does not require notes to be organized into a rigid page structure; users can click anywhere on a page and start typing or drawing, which has made it popular for freeform brainstorming, lecture notes, and handwritten annotation on touch devices.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include a free-form canvas for typed and handwritten notes, a web clipper browser extension, audio note recording with text search inside recordings, and tight integration with Outlook (meeting notes) and Microsoft Teams.$q$, $q$Microsoft 365 subscribers also gain access to Copilot-powered AI features for summarizing and organizing notes, plus additional cloud storage and cross-app integration with Word, Excel, and PowerPoint.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('118f8753-a6ca-4e1e-90db-108a98a53646', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OneNote's standalone app is free, including unlimited notes and 5GB of OneDrive storage, and does not require a Microsoft 365 subscription to use.$q$, $q$Microsoft 365 subscriptions, ranging from $9.99/month (Personal) to $19.99/month (Premium), unlock Copilot AI features inside OneNote along with the rest of the Office app suite and expanded cloud storage.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Next Action selling system$q$, $q$Every contact is assigned a single, concrete next action that surfaces in a prioritized action stream, keeping sales reps focused on follow-up.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Visual sales pipeline$q$, $q$A drag-and-drop pipeline view for tracking deals through custom stages alongside the Next Action queue.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Email integration and templates$q$, $q$Send and track emails from within the CRM using reusable templates and two-way email sync.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Web forms for lead capture$q$, $q$Embeddable web forms feed new leads directly into the CRM with automatic contact creation.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Workflow automation$q$, $q$Automation rules trigger follow-up tasks and status changes based on contact activity.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Customizable tags and fields$q$, $q$Flexible tagging and custom fields let small teams adapt the CRM to their specific sales process.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Team collaboration$q$, $q$Shared notes and communication history keep small sales teams aligned on account context.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Next Action system provides clear daily focus, reducing decision paralysis common in larger CRMs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Fast onboarding and minimal learning curve compared to enterprise CRM platforms$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Lightweight, uncluttered interface with no unnecessary bloat$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Affordable entry pricing well suited to small businesses and solo founders$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Responsive, small-team customer support$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$No permanently free plan, only a 21-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Fewer advanced reporting and customization options than larger CRMs like Salesforce or HubSpot$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Smaller third-party integration ecosystem than major CRM competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Business plan pricing at $19.95/user/month may be steep for very small teams needing advanced features$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Mobile app functionality is more limited than the desktop web experience$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$What is the Next Action system in OnePageCRM?$q$, $q$The Next Action system assigns every contact a single, concrete follow-up task, which appears in a prioritized action stream. It is based on Getting Things Done (GTD) methodology applied to sales, designed to keep reps focused on what to do next rather than passively browsing a dashboard.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$How much does OnePageCRM cost?$q$, $q$OnePageCRM's Professional plan starts at $9.95 per user per month (annual billing), and the Business plan is $19.95 per user per month. There is no permanent free plan, but a 21-day free trial is available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Who is OnePageCRM best suited for?$q$, $q$OnePageCRM is designed for small and medium-sized businesses, solo founders, freelancers, and small sales teams who find larger CRMs like Salesforce too complex or expensive.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Where is OnePageCRM based?$q$, $q$OnePageCRM was founded in 2010 and is headquartered in Galway, Ireland, with a small team of roughly 20-25 employees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Does OnePageCRM integrate with email?$q$, $q$Yes, OnePageCRM offers email integration and templates, allowing users to send and track emails directly from within the CRM.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$How does OnePageCRM compare to Pipedrive?$q$, $q$Both target small businesses with simple, focused CRMs. OnePageCRM emphasizes its action-oriented Next Action queue, while Pipedrive centers more on a visual deal pipeline, though the two overlap significantly in target audience and pricing tier.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Is there a free trial for OnePageCRM?$q$, $q$Yes, OnePageCRM offers a 21-day free trial on its paid plans, with no permanent free tier.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Solo founder sales tracking$q$, $q$Solo founders and freelancers use the Next Action queue to stay on top of every lead without needing a full sales operations setup.$q$, $q$Solo founders and freelancers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Small B2B sales team pipeline management$q$, $q$Small sales teams track deals through a visual pipeline while ensuring every contact has a clear follow-up action assigned.$q$, $q$Small B2B sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Consulting and professional services client follow-up$q$, $q$Consulting firms use OnePageCRM to manage client relationships and ensure timely follow-up on proposals and engagements.$q$, $q$Consulting and professional services firms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Professional$q$, $q$$9.95/user/month$q$, $q$Annual (higher if billed monthly)$q$, NULL, $q$["Next Action selling system","Sales pipeline","Contact management","Email integration","21-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$Business$q$, $q$$19.95/user/month$q$, $q$Annual (higher if billed monthly)$q$, NULL, $q$["Everything in Professional","Advanced automation","Advanced reporting","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OnePageCRM is a small-business CRM built around a single organizing principle: every contact should have one clear next action. Founded in 2010 in Galway, Ireland, the company built its product philosophy on Getting Things Done (GTD) methodology applied to sales pipelines.$q$, $q$Rather than a traditional dashboard-heavy CRM, OnePageCRM presents an action stream where sales reps see exactly what to do next for each lead or deal, reducing the cognitive overhead common in larger, more complex CRM platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core Next Action system assigns every contact a single follow-up task, which surfaces in a prioritized queue similar to an email inbox. Alongside this, OnePageCRM offers a visual sales pipeline, email templates and integration, and web forms for capturing leads directly into the CRM.$q$, $q$Additional capabilities include workflow automation rules, basic lead scoring, customizable tags and fields, and team collaboration tools like shared notes and shared communication history, all wrapped in a deliberately lightweight, low-clutter interface.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7effa4cf-f18e-4d12-bf52-83b570f6c948', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OnePageCRM has no permanently free tier but offers a 21-day free trial. The Professional plan starts at $9.95 per user per month on an annual billing cycle, covering the core Next Action CRM, pipeline, and contact management features.$q$, $q$The Business plan is $19.95 per user per month and adds more advanced automation and reporting for growing teams. Annual billing includes several months free compared to month-to-month pricing.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Multi-channel messaging$q$, $q$Send push notifications, email, SMS, and in-app messages from a single unified dashboard and API.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Automated messaging journeys$q$, $q$Build multi-step, triggered messaging flows based on user behavior and lifecycle stage.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Audience segmentation$q$, $q$Segment users by behavior, custom data tags, and engagement history for targeted campaigns.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Intelligent Delivery$q$, $q$Automatically optimizes send timing for each user to maximize open and engagement rates.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$A/B testing$q$, $q$Test message variants across channels to optimize copy, timing, and creative.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Cross-platform SDKs$q$, $q$Native SDKs for iOS, Android, web, Unity, React Native, Flutter, and Cordova simplify integration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Delivery and conversion analytics$q$, $q$Track delivery rates, opens, clicks, and conversions across all messaging channels.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Generous free tier with unlimited mobile push notifications makes it accessible for small apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Delivers billions of messages daily, demonstrating proven scale and reliability$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Broad SDK support across iOS, Android, web, Unity, React Native, Flutter, and Cordova$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Unified multi-channel approach avoids stitching together separate push, email, and SMS tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Backed by significant venture funding ($84.2M), supporting continued product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Usage-based pricing on the Growth plan can become costly as email and push volume scales$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Professional and Enterprise pricing is custom and not transparently published$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Advanced personalization and journey features are gated behind higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Smaller brand recognition in the enterprise segment compared to Braze or Iterable$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Free plan's single active journey limit is restrictive for more complex campaigns$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Is OneSignal free to use?$q$, $q$Yes, OneSignal offers a free plan that includes 10,000 monthly email sends and unlimited mobile push notification sends, along with basic segmentation and A/B testing, suitable for small apps and early-stage products.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$How much does OneSignal cost beyond the free plan?$q$, $q$The Growth plan starts at $19/month plus usage-based costs (for example, $1.50 per 1,000 emails beyond the included allotment, and $0.012 per monthly active user for mobile push). Professional and Enterprise tiers use custom, volume-based pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$What channels does OneSignal support?$q$, $q$OneSignal supports mobile push notifications, web push notifications, email, SMS, and in-app messaging, all managed from a single dashboard.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Who founded OneSignal and when?$q$, $q$OneSignal was founded in 2011 by George Deglin and Long Vo, and is headquartered in San Mateo, California.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$How does OneSignal compare to Firebase Cloud Messaging?$q$, $q$Firebase Cloud Messaging is a free, more basic push notification service from Google, while OneSignal offers a more full-featured platform with segmentation, automated journeys, multi-channel messaging, and analytics, available on both free and paid tiers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Does OneSignal support automated messaging journeys?$q$, $q$Yes, OneSignal supports multi-step automated messaging journeys, with the number of active journeys and steps expanding across higher-priced plans.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$How much venture funding has OneSignal raised?$q$, $q$OneSignal has raised approximately $84.2 million in total funding across multiple rounds, from investors including SignalFire, Y Combinator, and HubSpot.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Mobile app re-engagement$q$, $q$Mobile app developers use OneSignal push notifications to re-engage inactive users and drive app opens.$q$, $q$Mobile app developers and product teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$E-commerce transactional and marketing messaging$q$, $q$E-commerce businesses combine email, SMS, and push notifications through OneSignal for cart abandonment and promotional campaigns.$q$, $q$E-commerce and D2C brands$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Web app onboarding and lifecycle messaging$q$, $q$SaaS product teams build automated onboarding journeys combining in-app messages, email, and push notifications to guide new users.$q$, $q$SaaS product and growth teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Free$q$, $q$$0/month$q$, $q$Monthly$q$, NULL, $q$["10,000 monthly email sends","Unlimited mobile push sends","1 active messaging journey","6 audience segments","Basic A/B testing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Growth$q$, $q$From $19/month + usage$q$, $q$Monthly$q$, NULL, $q$["Usage-based email and push pricing","Unlimited in-app messaging","3 active journeys","10 audience segments","Advanced A/B testing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Professional$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["20 active journeys","Advanced personalization","Conversion metrics tracking","Dedicated IP option","24/7 prioritized support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Unlimited active journeys","Frequency capping","Dedicated success manager","Extended audit logs","SLA available"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$OneSignal is a customer engagement platform that unifies push notifications, email, SMS, and in-app messaging for mobile and web applications. Founded in 2011 in San Mateo, California, it has grown into one of the most widely used messaging infrastructure providers, delivering more than 8 billion messages per day.$q$, $q$The platform is particularly popular among app developers because of its generous free tier and straightforward SDK integration across major mobile and web platforms, making it a common default choice for startups and indie developers before they scale into larger engagement platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$OneSignal supports multi-channel messaging (push, email, SMS, in-app) from a single dashboard, with audience segmentation, automated multi-step messaging journeys, and A/B testing built in.$q$, $q$Its 'Intelligent Delivery' feature optimizes send timing per individual user, and the platform provides delivery analytics, conversion tracking, and GDPR-compliant data handling for teams operating in regulated markets.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8fe2e620-1117-42fb-88de-78ba0088f595', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$OneSignal's Free plan covers 10,000 monthly email sends and unlimited mobile push notifications, making it usable at no cost for small apps.$q$, $q$The Growth plan starts at $19/month plus usage-based fees, while Professional and Enterprise tiers offer custom, volume-based pricing with expanded journeys, segments, and support for larger organizations.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Real-time location tracking$q$, $q$View the current location and location history of enrolled Android devices from a self-hosted dashboard.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Remote device commands$q$, $q$Send ring and lock commands remotely to help locate or secure a lost or stolen device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Location sharing$q$, $q$Share a device's location with trusted friends or family members.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$De-Googled device support$q$, $q$Built specifically to work on Android distributions without Google Play Services, such as GrapheneOS and LineageOS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Home Assistant integration$q$, $q$Incorporate device location data into Home Assistant automations and dashboards.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Self-hosted data ownership$q$, $q$All location data stays on infrastructure the user controls, with no third-party cloud dependency.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Multiple installation channels$q$, $q$Android client available via F-Droid, direct GitHub releases, and Obtainium.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Completely free and open source with no paid tiers or hidden costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Full data ownership since all location data stays on self-hosted infrastructure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Purpose-built for de-Googled Android devices that lack access to Google's Find My Device$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Includes Find My Device-style remote commands like ring and lock, not just passive tracking$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Home Assistant integration extends functionality into broader smart-home setups$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Requires technical ability to self-host, unlike consumer-friendly commercial alternatives$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$No official mobile app for iOS, limiting it to Android devices$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Community-maintained project with no formal support SLA or dedicated company backing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Smaller feature set than mature commercial fleet-tracking or family-safety apps$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Relies on the user maintaining their own server uptime and security patching$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Is Onloc free to use?$q$, $q$Yes, Onloc is completely free and open source. There are no paid tiers or subscription fees; users only pay for their own server hosting if they choose to use a VPS rather than a home server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Do I need to self-host Onloc?$q$, $q$Yes, Onloc is a self-hosted platform. Users deploy the API and web frontend on their own server, commonly via Docker, and there is no official managed cloud version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Does Onloc work without Google Play Services?$q$, $q$Yes, Onloc was built specifically to support de-Googled Android devices, including distributions like GrapheneOS, LineageOS, and CalyxOS, where Google's Find My Device is unavailable.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$What remote commands can Onloc send to a device?$q$, $q$Onloc supports remote commands including ring (to help locate a nearby device) and lock (to help secure a lost or stolen device).$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$How do I install the Onloc Android app?$q$, $q$The Onloc Android client can be installed via F-Droid, downloaded directly from GitHub releases, or installed and auto-updated through Obtainium.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Does Onloc support iOS devices?$q$, $q$No, Onloc's client app is currently Android-only, targeting de-Googled and privacy-focused Android users specifically.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Who maintains Onloc?$q$, $q$Onloc is maintained by a community of open-source contributors credited as 'Onloc Maintainers,' rather than a commercial company, with development happening in the open on GitHub.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$De-Googled phone tracking$q$, $q$Users running GrapheneOS, LineageOS, or similar de-Googled Android distributions use Onloc to regain Find My Device-style tracking without Google services.$q$, $q$Privacy-focused Android users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Self-hosted family device sharing$q$, $q$Families share device locations with each other through a self-hosted Onloc instance instead of a third-party cloud service.$q$, $q$Privacy-conscious families and households$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Smart-home location automation$q$, $q$Home Assistant users integrate Onloc device location data into automations, such as adjusting climate or lighting based on arrival.$q$, $q$Self-hosting and home automation enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$Self-hosted (Free)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Real-time and historical location tracking","Remote ring and lock commands","Location sharing","Home Assistant integration","Full source code access"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Onloc is a free, open-source, self-hosted alternative to Google's Find My Device, built specifically with de-Googled Android users in mind. It lets device owners track location history, share location with trusted contacts, and send remote commands like ring and lock to their own devices.$q$, $q$The project is community-maintained rather than run by a commercial company, and is split across several open-source repositories covering the backend API, Android client, and web frontend, all of which users deploy on their own server infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Onloc's core feature is real-time and historical device location tracking, viewable through a self-hosted web frontend. Device owners can also send remote commands, including ring and lock, to help recover a lost or stolen device.$q$, $q$The Android client is distributed through F-Droid, GitHub releases, and Obtainium, and the platform includes a Home Assistant integration for incorporating device location into broader home automation setups.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Onloc is entirely free and open source, with no paid tiers, subscriptions, or licensing fees. Users are responsible only for the cost of hosting their own server, such as a small VPS or home server running Docker.$q$, $q$Because there is no commercial entity behind Onloc, there are no enterprise or support-tier pricing options; support comes from the open-source community via GitHub.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e1493d3f-721d-4cee-8c01-f904dc3274ec', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Full office editor suite$q$, $q$Online and desktop editors for text documents, spreadsheets, presentations, and PDFs with strong Microsoft Office format compatibility.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Fillable forms editor$q$, $q$Create and fill out interactive PDF and OFORM forms directly within the suite.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Real-time co-editing$q$, $q$Multiple users can edit documents simultaneously with live cursors, comments, and version tracking.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$On-premises deployment$q$, $q$Fully self-hostable on an organization's own infrastructure for data sovereignty and compliance needs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Open-source Community edition$q$, $q$A free, open-source edition of ONLYOFFICE Docs available for individuals and small teams.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Workspace collaboration suite$q$, $q$Optional bundled email, CRM, project management, and document management modules beyond the core editors.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Third-party integrations$q$, $q$Ready-to-use connectors for platforms like Nextcloud, Confluence, ownCloud, and various DMS systems.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Available fully self-hosted on-premises, unlike cloud-only competitors like Google Workspace$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Free, open-source Community edition provides genuine no-cost access to core editing features$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Strong compatibility with Microsoft Office file formats reduces migration friction$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Flexible licensing (1-year or lifetime) gives organizations control over long-term costs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Global support office footprint across Europe, Asia, and North America$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Enterprise pricing starting at $1,500/year for 50 users can be a significant upfront cost for small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Real-time collaboration and polish can lag slightly behind Google Docs or Microsoft 365 in some edge cases$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Self-hosting requires ongoing server maintenance and IT resources$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Support response times vary significantly by tier (Basic support has a 48-hour response window)$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Smaller ecosystem of third-party templates and add-ons compared to Microsoft or Google$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Is ONLYOFFICE free to use?$q$, $q$Yes, ONLYOFFICE offers a free, open-source Community edition of its Docs editors and a free personal cloud plan. The Enterprise edition, which starts at $1,500/year for 50 users, adds enhanced security, support, and deployment options.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Can ONLYOFFICE be self-hosted?$q$, $q$Yes, ONLYOFFICE can be fully self-hosted on-premises, which is one of its main differentiators from cloud-only suites like Google Workspace and standard Microsoft 365.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Is ONLYOFFICE compatible with Microsoft Office files?$q$, $q$Yes, ONLYOFFICE offers strong compatibility with Microsoft Office formats including .docx, .xlsx, and .pptx, making it easier for organizations to migrate from Microsoft Office.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Who develops ONLYOFFICE?$q$, $q$ONLYOFFICE is developed by Ascensio System SIA, a company founded in 2009 and headquartered in Riga, Latvia, led by founder and CEO Lev Bannov.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$What is the difference between ONLYOFFICE Docs and Workspace?$q$, $q$ONLYOFFICE Docs is the core document, spreadsheet, and presentation editor suite. ONLYOFFICE Workspace is a broader collaboration platform that adds email, CRM, project management, and document management on top of the Docs editors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$How much does ONLYOFFICE Enterprise cost?$q$, $q$ONLYOFFICE Docs Enterprise starts at $1,500 per year for a license covering 50 user connections, with options for cloud or on-premises deployment and a choice between a renewable 1-year license or a lifetime license.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$What are ONLYOFFICE's main alternatives?$q$, $q$Its main competitors include Microsoft 365, Google Workspace, LibreOffice, Collabora Online, and Zoho Office Suite.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Compliance-driven document editing$q$, $q$Regulated organizations like government agencies, healthcare, and finance self-host ONLYOFFICE on-premises to keep document data within their own infrastructure.$q$, $q$Regulated enterprises and government agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Cost-conscious Microsoft Office replacement$q$, $q$Small businesses and individuals use the free Community edition or personal cloud plan as a no-cost alternative to Microsoft 365 or Google Workspace.$q$, $q$Small businesses and individual users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Collaborative document platforms via integrations$q$, $q$Organizations running Nextcloud, ownCloud, or a document management system integrate ONLYOFFICE as the embedded editor for real-time collaborative editing.$q$, $q$IT teams running self-hosted collaboration platforms$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source Docs editors","Self-hosted deployment","Basic collaboration features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Personal Cloud$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Cloud-hosted editors for individuals","Limited storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$Docs Enterprise$q$, $q$From $1,500/year$q$, $q$Annual or lifetime license$q$, NULL, $q$["50 user connections","Cloud or on-premises deployment","Enhanced security features","Professional support (Basic, Plus, or Premium tiers)","All minor and major updates"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$ONLYOFFICE is an office productivity suite developed by Ascensio System SIA, founded in 2009 and headquartered in Riga, Latvia. It provides online and desktop editors for documents, spreadsheets, presentations, forms, and PDFs, with strong compatibility for Microsoft Office file formats.$q$, $q$What sets ONLYOFFICE apart from Microsoft 365 and Google Workspace is deployment flexibility: it is available as a free, open-source Community edition that organizations can self-host on-premises, in addition to cloud-hosted and licensed Enterprise options.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ONLYOFFICE Docs offers full-featured document, spreadsheet, presentation, form, and PDF editors, accessible via web browser, desktop app, or mobile app, with real-time co-editing and commenting for team collaboration.$q$, $q$ONLYOFFICE Workspace expands the offering with email, CRM, project management, and document management modules, while ONLYOFFICE DocSpace focuses on room-based document sharing and external collaboration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$ONLYOFFICE Docs Enterprise starts at $1,500 per year for a 50-user license, available as cloud-hosted or on-premises, with a choice of a renewable 1-year license or a lifetime license including three years of updates.$q$, $q$A free, open-source Community edition and a free personal cloud plan are also available for individuals and small teams, with paid support tiers and add-ons like disaster recovery and training available for Enterprise customers.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ab659340-1acd-4acc-9653-f4c90a759519', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$AI chat grounded in company data$q$, $q$A ChatGPT-style assistant that answers questions using retrieval-augmented generation over indexed internal knowledge sources.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$40+ knowledge source connectors$q$, $q$Native connectors to Slack, Google Drive, Confluence, Salesforce, GitHub, and dozens of other enterprise tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Custom AI agents$q$, $q$Build task-specific AI agents that can take actions across connected systems, not just answer questions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$LLM provider flexibility$q$, $q$Works with any LLM provider, including OpenAI, Anthropic, and self-hosted open-weight models.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Deep research workflows$q$, $q$Multi-step research capabilities that synthesize answers across many connected knowledge sources.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$MCP tool integration$q$, $q$Supports the Model Context Protocol for connecting AI agents to external tools and actions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Self-hosted deployment$q$, $q$Deployable via Docker, Kubernetes, or Helm/Terraform for full data control and on-premises compliance.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Community Edition is genuinely free and MIT-licensed with the full core feature set, not a crippled trial$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Works with any LLM provider, avoiding vendor lock-in to a single AI model$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Broad library of 40+ pre-built connectors to common enterprise knowledge sources$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Backed by significant venture funding ($10M seed from Khosla Ventures and First Round Capital), supporting active development$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Self-hosting option gives full data control for compliance-sensitive organizations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Self-hosting requires technical infrastructure expertise (Docker/Kubernetes) to deploy and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Enterprise governance features like SSO, SCIM, and audit trails require the paid Enterprise Edition$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Managed Cloud pricing (from $16-20/seat/month) is per-seat, which can scale up quickly for larger teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Younger company (founded 2023) with a smaller support and services organization than established competitors like Glean$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Rebrand from Danswer to Onyx may cause confusion when researching historical reviews or documentation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Is Onyx the same as Danswer?$q$, $q$Yes. Onyx was originally launched under the name Danswer before the company rebranded to Onyx. The underlying open-source project and GitHub organization now use the Onyx name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Is Onyx Community Edition really free?$q$, $q$Yes, Onyx Community Edition is free and open source under the MIT license, and includes the full core feature set for Chat, RAG, Agents, and Actions when self-hosted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$What is the difference between Onyx Community and Enterprise Edition?$q$, $q$Community Edition covers the core AI chat, search, and agent features for free. Enterprise Edition adds governance and compliance features like SOC 2 Type II, SSO via OIDC/SAML, SCIM identity provider integration, granular RBAC, and audit trails, available via custom pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Can I self-host Onyx?$q$, $q$Yes, Onyx supports self-hosted deployment via Docker, Kubernetes, or Helm/Terraform, giving organizations full control over their data and infrastructure.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$How much does Onyx Cloud cost?$q$, $q$Onyx's managed Cloud plan starts at approximately $16-20 per seat per month depending on billing terms, with Enterprise pricing available on request for larger deployments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Who founded Onyx?$q$, $q$Onyx was founded in 2023 by Yuhong Sun and Chris Weaver, and is headquartered in San Francisco. The company raised a $10 million seed round co-led by Khosla Ventures and First Round Capital.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Which LLM providers does Onyx support?$q$, $q$Onyx is LLM-agnostic and works with commercial providers like OpenAI and Anthropic as well as self-hosted open-weight models, letting organizations choose based on cost, performance, or compliance needs.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Internal enterprise knowledge search$q$, $q$Organizations index Slack, Confluence, Google Drive, and other internal tools so employees can ask natural-language questions and get grounded answers.$q$, $q$IT and knowledge management teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Compliance-sensitive AI deployment$q$, $q$Regulated organizations self-host Onyx Community or Enterprise Edition to keep proprietary data and AI processing entirely within their own infrastructure.$q$, $q$Regulated enterprises and government agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Custom AI agent development$q$, $q$Technical teams build custom AI agents on top of Onyx that can search company data and take actions across connected systems via MCP.$q$, $q$Engineering and AI platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Community Edition$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Chat, RAG, Agents, and Actions feature set","40+ knowledge source connectors","Self-hosted via Docker/Kubernetes","MIT license","Any LLM provider"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Cloud$q$, $q$~$16-20/seat/month$q$, $q$Monthly or annual$q$, NULL, $q$["Managed hosting","Core Community Edition features","No infrastructure management required"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$Enterprise Edition$q$, $q$Custom$q$, $q$Annual contract$q$, NULL, $q$["SOC 2 Type II compliance","SSO via OIDC and SAML","SCIM/identity provider integration","Granular role-based access control","Audit trails","Self-hosted or cloud deployment"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Onyx is an open-source AI platform for enterprise search, retrieval-augmented generation, and AI agents, founded in 2023 by Yuhong Sun and Chris Weaver in San Francisco. The project was originally launched under the name Danswer before rebranding to Onyx.$q$, $q$Onyx Community Edition is the free, MIT-licensed, self-hostable version of the platform, offering the complete core feature set rather than a limited trial, letting technical teams build an internal AI assistant grounded in their own company data.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Onyx connects to more than 40 knowledge sources, including Slack, Google Drive, Confluence, Salesforce, and GitHub, indexing internal content so users can ask natural-language questions and get answers grounded in that data via retrieval-augmented generation.$q$, $q$The platform supports custom AI agents, deep research workflows across connected sources, Model Context Protocol (MCP) integration for tool use, and works with any LLM provider, letting organizations choose between commercial APIs like OpenAI and Anthropic or self-hosted open-weight models.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Onyx Community Edition is completely free and open source under the MIT license, with no artificial feature limits on core Chat, RAG, Agents, and Actions capabilities for self-hosted deployments.$q$, $q$Onyx also offers a managed Cloud plan starting around $16-20 per seat per month for teams that prefer not to manage infrastructure, plus a custom-priced Enterprise Edition adding SOC 2 compliance, SSO, SCIM, and audit trails for larger organizations.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
