-- Enrichment marathon batch: OneDev, Oneflow, OneNote, OnePageCRM, OneSignal, Onloc, ONLYOFFICE, Onyx Community Edition

-- ── OneDev ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OneDev is a free, open-source, self-hosted DevOps platform that unifies Git repository hosting, CI/CD pipelines, kanban-style issue tracking, code search, and package registries into a single Java application.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Enterprise Edition from $6/user/month$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Small open-source maintainer team$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OneDev Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OneDev review 2026: an all-in-one self-hosted Git server with built-in CI/CD, kanban issue tracking, and package registries. Compare features, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OneDev is an open-source, self-hosted DevOps platform created by developer Robin Shen that unifies Git repository management, a Kubernetes-native CI/CD engine, kanban-style issue tracking, code search and navigation, and built-in package registries (Docker, NPM, Maven, NuGet, PyPI, RubyGems, Helm) into a single Java application distributed as one Docker image. Its core differentiator versus GitLab or Gitea is depth of integration: pull requests, CI/CD jobs, and issues share the same data model, so reviewers can jump between commits, builds, and tickets without leaving the app, and CI/CD jobs can be authored through a visual GUI instead of hand-written YAML. OneDev also includes per-commit code search by symbol, file, or regular expression; inline commenting on any code snippet without opening a pull request; customizable issue states and fields; an email-based service desk; LDAP/Active Directory authentication with SSO and two-factor auth; and more recently AI-assisted user task assignment. The project is hosted on GitHub at theonedev/onedev with over 15,000 stars and nearly 500 releases, with active development continuing through 2026 (latest release v16.2.0). OneDev ships two editions: the Community Edition is completely free and open source, covering the full DevOps toolchain described above and suitable for individual developers, small teams, and self-hosters who want a GitLab alternative without licensing costs. The Enterprise Edition costs $6 per user per month (12 user-month minimum) and adds high-availability clustering without shared storage, cross-project code search, built-in security and secret scanning, Renovate dependency-update integration, audit logging, time tracking and timesheets, a web terminal for debugging CI/CD jobs, SendGrid and Microsoft Teams integrations, and priority email support with a two-business-day response guarantee. OneDev targets engineering teams, DevOps engineers, and self-hosting enthusiasts who want to consolidate Git hosting, CI/CD, and issue tracking into one lightweight tool rather than stitching together GitHub, Jenkins, and Jira separately. Its primary competitors are GitLab (self-managed and SaaS), Gitea and its fork Forgejo, SourceHut, and Codeberg, though OneDev distinguishes itself with a built-in visual CI/CD job editor and tighter cross-feature integration for a single maintainer-led, low-overhead product. It deploys via Docker, bare-metal installers, or Kubernetes and is written entirely in Java.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9e5b2300-98f1-4d4e-93ad-dc29b5d2d9c5';

