-- ── Oneflow ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Oneflow is a Swedish contract lifecycle management platform that turns static PDF contracts into dynamic, data-rich digital documents with e-signing, templates, and workflow automation.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (basic PDF signing); paid plans from EUR17/user/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$100-250 employees$q$, company_size),
  headquarters = COALESCE($q$Stockholm, Sweden$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Swedish$q$]::text[],
  seo_title = COALESCE($q$Oneflow Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Oneflow review 2026: contract lifecycle management with e-signing, templates and automation. See pricing plans, features, pros, cons and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Oneflow is a contract lifecycle management (CLM) platform founded in 2012 in Stockholm, Sweden by Anders Hamnes (CEO), Kalle Moodh, and Fredrik Rinman. Its core differentiator is treating contracts as structured, editable data rather than static PDF or Word documents: parties can negotiate, comment, and edit contract content live inside a shared digital document, with every field trackable as data that can feed dashboards, CRM systems like Salesforce and HubSpot, and reporting tools. Oneflow covers the full contract lifecycle, including template creation, collaborative drafting, legally binding e-signatures (including advanced and qualified signature levels for EU compliance), approval workflows, contract analytics, and post-signature lifecycle management such as renewal reminders and obligation tracking. The company went public in April 2022, listing its shares on Nasdaq First North Premier Growth Market in Stockholm, and as of 2026 employs roughly 127-159 people across offices in Sweden, Norway, and Finland, with customers across Europe and beyond. Oneflow's pricing is tiered: a Free plan allows sending and signing basic PDF contracts at no cost; the Essentials plan (around EUR17 per user per month) adds digital, data-driven contracts and templates; the Business plan (around EUR45 per user per month) adds contract lifecycle management, advanced workflow automation, and premium integrations; and an Enterprise plan offers custom pricing with dedicated support, advanced security, and API access for large organizations. Oneflow targets small and mid-sized businesses through enterprise sales, legal, HR, and procurement teams that need to move contract workflows away from manual PDF-and-email processes toward an auditable, integrated system. Its primary competitors include DocuSign (particularly DocuSign CLM), PandaDoc, Ironclad, Concord, and SignNow, with Oneflow differentiating itself through its 'living document' data model, native CRM integrations, and strong presence in the Nordic and broader European markets. As a publicly traded SaaS company, Oneflow publishes regular financial disclosures, which lends transparency around its growth trajectory that many private CLM competitors do not offer.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5508cca3-5bae-43ef-99a9-12d8e8bc4e09';

