-- ── OneNote ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OneNote is Microsoft's free digital notebook app for capturing, organizing, and syncing typed notes, handwriting, audio, and web clippings across Windows, Mac, mobile, and the web.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (standalone); premium AI features via Microsoft 365 from $9.99/month$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE($q$220,000+ employees (Microsoft Corporation)$q$, company_size),
  headquarters = COALESCE($q$Redmond, Washington, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and dozens of other languages via Microsoft 365 localization$q$]::text[],
  seo_title = COALESCE($q$OneNote Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OneNote review 2026: Microsoft's free digital notebook with typing, handwriting, and web clipping. Compare pricing, features and alternatives like Notion.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OneNote is Microsoft's digital note-taking application, first announced in 2002 and shipped in 2003 as a standalone product bundled with certain Office and Tablet PC configurations; it became a core part of the Microsoft Office suite starting with Office 2007 and today ships both as a free standalone app and as part of Microsoft 365. OneNote organizes content into notebooks, sections, and pages, and supports free-form input including typed text, handwritten ink (especially on touch and pen-enabled devices), audio recordings, images, and clipped web content via the OneNote Web Clipper browser extension. Notes sync automatically across Windows, macOS, iOS, Android, and the web through OneDrive, making it a cross-device capture tool for students, professionals, and teams. As of 2026, OneNote's standalone app remains free to use, including unlimited notes and 5GB of OneDrive cloud storage; Microsoft has continued to invest in the standalone free product even as it retired the older, separately coded 'OneNote for Windows 10' app in October 2025 in favor of unifying development around the main desktop OneNote application. Premium capabilities, most notably Microsoft 365 Copilot integration for AI-assisted note summarization and drafting, require a Microsoft 365 subscription, which ranges from Microsoft 365 Personal at $9.99/month up to Microsoft 365 Premium at $19.99/month, bundling OneNote with Word, Excel, PowerPoint, Outlook, and additional OneDrive storage. OneNote's target audience spans students taking lecture and research notes, professionals capturing meeting notes and project documentation, and teams using shared notebooks for collaborative knowledge bases, particularly within organizations already standardized on Microsoft 365 and Teams. Its most direct competitors are Evernote, a longtime rival note-taking app; Notion, which has captured significant mindshare among teams wanting databases and wikis alongside notes; Google Keep, a simpler free alternative tied to Google Workspace; and Apple Notes, the default option for Apple device users. OneNote's competitive advantage lies in deep integration with the rest of Microsoft 365 (Outlook meeting notes, Teams meeting integration, Office document embedding) and strong handwriting and ink support on Surface and other pen-enabled Windows devices, though it is generally viewed as less flexible than Notion for building structured databases or wikis.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '118f8753-a6ca-4e1e-90db-108a98a53646';

