-- ── OneSignal ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$OneSignal is a customer engagement platform for sending push notifications, email, SMS, and in-app messages, powering over 8 billion messages a day for mobile and web apps.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free; Growth plan from $19/month plus usage$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$150-200 employees$q$, company_size),
  headquarters = COALESCE($q$San Mateo, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$OneSignal Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$OneSignal review 2026: push notifications, email, SMS and in-app messaging for apps. Compare pricing plans, features and top alternatives like Braze.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$OneSignal is a customer engagement and messaging platform founded in 2011 by George Deglin and Long Vo, headquartered in San Mateo, California, and backed by roughly $84.2 million in total funding from investors including SignalFire, Y Combinator, and HubSpot. The platform unifies push notifications (mobile and web), email, SMS, and in-app messaging into a single dashboard, and by its own account delivers more than 8 billion messages per day, making it one of the most widely adopted messaging infrastructure providers for mobile and web developers. OneSignal's key differentiator versus larger customer engagement suites like Braze or Iterable is its free, generous entry tier combined with developer-friendly SDKs across iOS, Android, web, Unity, React Native, Flutter, and Cordova, which made it a default choice for indie developers and startups needing reliable push notifications without a steep initial cost. The platform includes audience segmentation, automated messaging journeys with multi-step flows, A/B testing, GDPR-compliant data handling, delivery analytics, and an 'Intelligent Delivery' feature that optimizes send timing per user. OneSignal's pricing follows a freemium, usage-based model: the Free plan includes 10,000 monthly email sends and unlimited mobile push notifications, with a single active messaging journey; the Growth plan starts at $19/month plus usage-based costs (email at $1.50 per 1,000 sends beyond the included allotment, mobile push at $0.012 per monthly active user, web push at $0.004 per subscriber) and unlocks unlimited in-app messaging and more journeys and segments; the annually billed Professional tier offers custom, volume-based pricing with expanded journeys, advanced A/B testing, conversion tracking, and a dedicated IP option; and the Enterprise tier offers fully custom contracts with unlimited journeys, frequency capping, a dedicated success manager, extended audit logs, and SLA guarantees. OneSignal targets mobile and web app developers, product teams, and growth/marketing teams at companies ranging from indie app studios to large consumer apps that need reliable, high-volume, multi-channel messaging infrastructure. Its primary competitors include Braze, Airship, CleverTap, Iterable, and Firebase Cloud Messaging (Google's free but more limited push notification service), with OneSignal generally positioned as the more developer-accessible, cost-effective option compared to enterprise-focused platforms like Braze.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8fe2e620-1117-42fb-88de-78ba0088f595';

