-- ── Onloc ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Onloc is a free, open-source, self-hosted device tracking platform that lets users locate, monitor, and remotely control their own Android devices without relying on Google's Find My Device service.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE($q$Community-maintained open-source project$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Onloc Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Onloc review 2026: a free, self-hosted, open-source device tracking tool for de-Googled Android phones. See features, setup, and alternatives like OwnTracks.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Onloc is a free, open-source, self-hosted device tracking and control platform designed primarily for de-Googled Android devices, giving privacy-conscious users a way to locate, monitor, and remotely control their own phones and devices without depending on Google's Find My Device or similar proprietary cloud services. The project is maintained by a community of open-source contributors (credited on the project as 'Onloc Maintainers' rather than a commercial company) and is distributed across several GitHub repositories: the main onloc deployment repository, an onloc-api backend that manages location data, an onloc-android client app, and a web frontend for managing devices and viewing location history. Core functionality includes real-time and historical location tracking of enrolled devices, the ability to send remote commands such as ring and lock to a lost or stolen device, and sharing device location with trusted friends or family members. Because it is self-hosted, all location data stays on infrastructure the user controls rather than being sent to a third-party cloud provider, which is the platform's central value proposition for privacy-focused users, including those running de-Googled Android distributions like GrapheneOS, LineageOS, or CalyxOS where Google's own Find My Device is unavailable. The Android client can be installed through F-Droid, direct GitHub releases, or Obtainium, all common distribution channels for privacy-respecting open-source Android apps. Onloc also offers a Home Assistant integration, letting users incorporate device location into broader smart-home automations. Onloc is entirely free with no paid tiers, monetization, or company behind it; users self-host the API and frontend (for example via Docker) on their own server or a small VPS, and there is no subscription or licensing cost. Its target audience is privacy-focused individuals, self-hosting enthusiasts, and de-Googled Android users who want Find My Device-style functionality without sending location data to Google or any third party. Its closest competitors and alternatives include OwnTracks (a longer-established self-hosted location-sharing tool), Traccar (a more general-purpose open-source GPS tracking platform), Nextcloud's location-sharing capabilities, and GPSLogger, with Onloc differentiating itself through its specific focus on Find My Device-style remote device commands (ring, lock) rather than pure location logging.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e1493d3f-721d-4cee-8c01-f904dc3274ec';

