-- ── Onyx Community Edition ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Onyx Community Edition is the free, MIT-licensed, open-source version of Onyx (formerly Danswer), an AI enterprise search and assistant platform that connects to 40+ knowledge sources for chat, RAG, and autonomous agents.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free (Community Edition); Cloud from $16-20/seat/month$q$, starting_price),
  founded_year = COALESCE(2023, founded_year),
  company_size = COALESCE($q$11-50 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Onyx Community Edition Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Onyx Community Edition review 2026: free, open-source AI enterprise search (formerly Danswer). Compare features, self-hosting, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Onyx is an open-source AI platform for enterprise search, retrieval-augmented generation (RAG), and AI agents, founded in 2023 by Yuhong Sun and Chris Weaver and headquartered in San Francisco. The company was originally known as Danswer before rebranding to Onyx, and it raised a $10 million seed round co-led by Khosla Ventures and First Round Capital, with participation from Y Combinator and angel investors including Gokul Rajaram, Arash Ferdosi, and Amit Agarwal; it employs roughly 20 people as of its most recent public profile. Onyx Community Edition (CE) is the fully free, MIT-licensed, self-hostable version of the platform, and unlike many 'open core' products, it is not a stripped-down trial: Onyx states that CE includes the complete core feature set for Chat, RAG, Agents, and Actions, including connectors to more than 40 knowledge sources such as Slack, Google Drive, Confluence, Salesforce, and GitHub, letting organizations build an internal, ChatGPT-style assistant that can answer questions grounded in their own private data while working with any LLM provider of their choice (OpenAI, Anthropic, self-hosted open-weight models, etc.). Beyond basic chat and search, Onyx supports building custom AI agents, deep research workflows across connected knowledge sources, and integration with the Model Context Protocol (MCP) for tool use. For organizations that do not want to manage self-hosted infrastructure, Onyx also offers a managed Cloud edition starting around $16-20 per seat per month (with a higher monthly, lower annual rate), and an Enterprise Edition (EE) — available both self-hosted and in the cloud — that adds enterprise governance features including SOC 2 Type II compliance, SSO via OIDC and SAML, SCIM/identity provider integration, granular role-based access control, and audit trails, priced via custom contracts. Onyx's target audience is engineering-savvy organizations, IT and data teams, and enterprises with strict data-residency or compliance requirements that need an AI search and assistant layer over internal knowledge without sending proprietary data to a third-party SaaS vendor, as well as smaller technical teams that want a capable, free, self-hosted AI knowledge assistant. Its primary competitors include Glean (a well-funded enterprise search leader), Guru, Elastic Enterprise Search, Microsoft Copilot for enterprise search scenarios, and Perplexity Enterprise, with Onyx differentiating itself through its genuinely open-source, MIT-licensed core and the option to self-host with full control over both data and choice of underlying LLM.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8c9db3fe-4234-4a92-8ea5-cf2dfcc5376c';

